const messageInput = document.getElementById('message-input');
const counterLabel = document.getElementById('counter-label');

messageInput.addEventListener('input', () => {
  const len = messageInput.value.length;
  counterLabel.textContent = `${len} / 100`;

  if (len > 100) {
    counterLabel.classList.add('text-red-500');
    counterLabel.classList.remove('text-slate-400');
    messageInput.classList.add('border-red-500', 'focus:border-red-500');
    messageInput.classList.remove('border-slate-700', 'focus:border-indigo-500');
  } else {
    counterLabel.classList.remove('text-red-500');
    counterLabel.classList.add('text-slate-400');
    messageInput.classList.remove('border-red-500', 'focus:border-red-500');
    messageInput.classList.add('border-slate-700', 'focus:border-indigo-500');
  }
});
